SourceCode.Declaration:
/// <summary>
/// Contract class for ETG Customer Transaction Grouping Report
/// </summary>
[DataContractAttribute]
class ETGCustTransGroupingContract
{
    TransDate fromDate;
    TransDate toDate;

}

Method.Source:
[DataMemberAttribute('FromDate')]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[DataMemberAttribute('ToDate')]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

/// <summary>
/// Validates the contract parameters
/// </summary>
/// <returns>True if valid, false otherwise</returns>
public boolean validate()
{
    boolean isValid = true;

    if (!fromDate)
    {
        error("From date is required");
        isValid = false;
    }

    if (!toDate)
    {
        error("To date is required");
        isValid = false;
    }

    if (fromDate && toDate && fromDate >= toDate)
    {
        error("To date should be greater than From date");
        isValid = false;
    }

    return isValid;
}
